const chatInput = ($input.first().json.chatInput || '').trim();
if (chatInput.length > 5000) throw new Error('Input too long (max 5000 chars)');

// Extract universeId from input (format: "universeId:univ-xxx theme text")
const match = chatInput.match(/^(univ-[a-z0-9-]+)\s*(.*)/i);
if (!match) throw new Error('Input must start with an existing universeId. Format: univ-xxx your theme here');

const universeId = match[1].trim();
const themeInput = match[2].trim();
const inputType = themeInput.length > 500 ? 'full_story' : 'theme';

return [{ json: { chatInput: themeInput, inputType, universeId } }];

const universeRows = $input.first().json;
const universe = Array.isArray(universeRows) ? universeRows[0] : universeRows;
if (!universe || !universe.id) throw new Error('Universe not found in DB');

let parseData = {};
try { parseData = $('Parse Input (universeId + theme)').first().json; } catch(e) {}

const avatarNames = universe.avatar_character_names || [];
const gender = universe.gender || 'girl';
const base = 'https://wddatxgqhdiosuhcztex.supabase.co/rest/v1/avatars';
let url = base + '?select=character_name,character_prompt,character_trait,gender';
if (avatarNames.length > 0) {
  url += '&character_name=in.(' + avatarNames.map(n => '"' + n + '"').join(',') + ')';
}

return [{ json: {
  chatInput: parseData.chatInput || '',
  inputType: parseData.inputType || 'theme',
  universeId: universe.id,
  universeName: universe.name || '',
  avatarGender: gender,
  avatarFetchUrl: url
} }];

const items = $input.all();
const rows = [];
items.forEach(i => {
  const j = i.json;
  if (Array.isArray(j)) rows.push(...j);
  else if (j && typeof j === 'object' && (j.character_name != null || j.body != null)) {
    if (Array.isArray(j.body)) rows.push(...j.body);
    else rows.push(j);
  }
});

let prevData = {};
try { prevData = $('Prepare avatar fetch').first().json; } catch(e) {}

const matched = {};
let firstGender = prevData.avatarGender || 'girl';
rows.forEach(r => {
  if (r.character_name) {
    matched[r.character_name] = {
      name: r.character_name,
      prompt: r.character_prompt || '',
      trait: r.character_trait || '',
      gender: r.gender || 'girl'
    };
    firstGender = r.gender || firstGender;
  }
});

const characterBible = Object.entries(matched)
  .map(([name, av]) => name + ': ' + av.prompt)
  .join('\n');

const characterTraits = Object.entries(matched)
  .map(([name, av]) => av.trait ? name + ': ' + av.trait : '')
  .filter(Boolean)
  .join('\n');

const fallback = 'Hana: fillette de 8 ans, cheveux noirs courts au carre, petit ruban rouge cote gauche, grands yeux vert emeraude, tunique bleue aventuriere bordures dorees, bottes cuir marron, pendentif etoile lumineux.';

return [{ json: {
  chatInput: prevData.chatInput || '',
  inputType: prevData.inputType || 'theme',
  universeId: prevData.universeId,
  avatarGender: firstGender,
  characterBible: characterBible || fallback,
  characterTraits,
  matchedCharacters: Object.keys(matched)
} }];

const data = $input.first().json;
const storyInput = (data.chatInput || '').trim();
const characterBible = data.characterBible || '';
const characterTraits = data.characterTraits || '';
const universeId = data.universeId;
const inputType = data.inputType || 'theme';

const taskBlock = inputType === 'full_story'
  ? '- Texte complet fourni. Decoupe en 2 histoires de 5 pages qui convergent.'
  : '- Theme fourni. Invente 2 histoires de 5 pages qui convergent vers la meme fin.';

const traitBlock = characterTraits
  ? '\nTRAITS DE PERSONNALITE (influencent les reactions, decisions et arc narratif) :\n' + characterTraits + '\n'
  : '';

const fullPrompt = `Tu es un auteur narratif manga pour enfants (6-10 ans). Tu crees une histoire interactive avec 2 CHEMINS qui CONVERGENT.

=== CONCEPT ===
L'enfant choisit entre 2 accroches (story_starts). Selon son choix, il voit 5 pages. Les 2 chemins divergent au debut (pages 1-2) puis convergent (pages 3-4-5).

=== BIBLE VISUELLE ===
${characterBible}
=== FIN BIBLE VISUELLE ===
${traitBlock}
ENTREE UTILISATEUR :
${storyInput || '(aucun theme - invente une aventure a branches)'}

IDENTIFIANT UNIVERS : ${universeId}

=== STORY STARTS (2 accroches) ===
- 2 story_starts : 1 titre (max 6 mots) + 1 phrase d'accroche.
- start-A a first_page_id = "p1a", start-B a first_page_id = "p1b".

=== STRUCTURE : 7 PAGES (5 par parcours, 2 chemins) ===
PAGES DIVERGENTES :
- p1a : Ouverture chemin A (4-5 phrases). 2 choix -> p2a.
- p1b : Ouverture chemin B (4-5 phrases). 2 choix -> p2b.
- p2a : Developpement A (2-3 phrases). 2 choix -> p3.
- p2b : Developpement B (2-3 phrases). 2 choix -> p3.

PAGES CONVERGENTES :
- p3 : CONVERGENCE (2-3 phrases). 2 choix -> p4.
- p4 : CLIMAX (2-3 phrases). 2 choix -> p5.
- p5 : FIN (2-3 phrases). choices = [].

TACHE :
${taskBlock}
- Chaque page a paragraph_text et scene_summary.
- Chaque choix a id, text (max 10 mots), next_page_id.
- Langue : francais, phrases simples, max 15 mots par phrase.

FORMAT : JSON strict, pas de markdown.

SCHEMA :
{
  "story_starts": [
    { "id": "start-A", "title": "max 6 mots", "text": "accroche A", "first_page_id": "p1a" },
    { "id": "start-B", "title": "max 6 mots", "text": "accroche B", "first_page_id": "p1b" }
  ],
  "pages": [
    { "page_id": "p1a", "paragraph_text": "...", "scene_summary": "...", "choices": [{ "id": "c-p1a-1", "text": "...", "next_page_id": "p2a" }, { "id": "c-p1a-2", "text": "...", "next_page_id": "p2a" }] },
    { "page_id": "p1b", "paragraph_text": "...", "scene_summary": "...", "choices": [{ "id": "c-p1b-1", "text": "...", "next_page_id": "p2b" }, ...] },
    { "page_id": "p2a", ..., "choices": [{ ..., "next_page_id": "p3" }] },
    { "page_id": "p2b", ..., "choices": [{ ..., "next_page_id": "p3" }] },
    { "page_id": "p3", ..., "choices": [{ ..., "next_page_id": "p4" }] },
    { "page_id": "p4", ..., "choices": [{ ..., "next_page_id": "p5" }] },
    { "page_id": "p5", ..., "choices": [] }
  ]
}

REGLES :
- Exactement 7 pages : p1a, p1b, p2a, p2b, p3, p4, p5.
- Parcours enfant = 5 pages (p1a->p2a->p3->p4->p5 OU p1b->p2b->p3->p4->p5).`;

return [{ json: { fullPrompt, universeId, avatarGender: data.avatarGender, matchedCharacters: data.matchedCharacters } }];

const raw = $input.first().json?.output?.[0]?.content?.[0]?.text;
if (!raw) throw new Error('No LLM output received.');

let cleaned = raw.trim();
if (cleaned.startsWith('```')) {
  cleaned = cleaned.replace(/```json/g, '').replace(/```/g, '').trim();
}

let parsed;
try { parsed = JSON.parse(cleaned); }
catch (e) { throw new Error('Invalid JSON: ' + e.message + ' | ' + cleaned.substring(0, 300)); }

let pages = parsed.pages || [];
if (pages.length === 0) throw new Error('No pages in LLM output.');

let promptData = {};
try { promptData = $('Build story prompt').first().json; } catch(e) {}
const universeId = promptData.universeId;
const avatarGender = promptData.avatarGender || 'girl';
const now = new Date().toISOString();

// Normalize LLM field names
pages = pages.map(p => ({
  ...p,
  page_id: p.page_id || p.pageId || null,
  paragraph_text: p.paragraph_text || p.paragraphText || '',
  scene_summary: p.scene_summary || p.sceneSummary || '',
  choices: (p.choices || []).map(c => ({ ...c, next_page_id: c.next_page_id || c.nextPageId || null })),
}));

const hasBranching = pages[0] && pages[0].page_id != null;
const pageIdToNumber = {};
if (hasBranching) {
  pages.forEach((p, i) => { if (p.page_id) pageIdToNumber[p.page_id] = i + 1; });
}

return pages.map((page, index) => {
  const pageNumber = hasBranching ? (index + 1) : (page.page_number || page.pageNumber || index + 1);
  let choices = page.choices || [];
  if (hasBranching && choices.length) {
    choices = choices.map(c => ({ ...c, next_page_number: c.next_page_id ? pageIdToNumber[c.next_page_id] : null }));
  }
  return {
    json: {
      universeId,
      pageNumber,
      pageId: page.page_id || ('p' + pageNumber),
      paragraphText: page.paragraph_text,
      sceneSummary: page.scene_summary,
      choices,
      storyStarts: parsed.story_starts || [],
      avatarGender,
      createdAt: now
    }
  };
});

const parseItem = $('Parse story JSON').first().json;
const starts = parseItem.storyStarts || [];
const universeId = parseItem.universeId;
if (!starts.length || !universeId) return [];

const ts = Date.now().toString(36);
const univSuffix = universeId.replace('univ-', '').substring(0, 8);

return starts.map(s => {
  const pathLabel = (s.id || 'start-x').toLowerCase();
  const pathSuffix = pathLabel.replace('start-', '');
  const rand = Math.random().toString(36).substring(2, 6);
  return {
    json: {
      id: `ss-${univSuffix}-${ts}-${rand}-${pathSuffix}`,
      path_id: s.id || pathLabel,
      first_page_id: s.first_page_id || s.firstPageId || null,
      universe_id: universeId,
      title: s.title || 'Sans titre',
      text: s.text || '',
    }
  };
});

const items = $input.all();
return items.filter(item => item.json.universeId && item.json.pageNumber).map(item => ({
  json: {
    universe_id: item.json.universeId,
    page_number: item.json.pageNumber,
    text: item.json.paragraphText || '',
    scene_summary: item.json.sceneSummary || '',
    created_at: item.json.createdAt
  }
}));

// Get universeId from parsed pages
const firstPage = $input.first().json;
const universeId = firstPage.universeId;
if (!universeId) throw new Error('No universeId to delete old choices');
return [{ json: { universeId } }];

const items = $('Parse story JSON').all();
const results = [];
const ts = Date.now().toString(36);
for (const item of items) {
  if (!item.json.universeId || !item.json.pageNumber) continue;
  const univSuffix = item.json.universeId.replace('univ-', '').substring(0, 8);
  const choices = item.json.choices || [];
  choices.forEach((choice, index) => {
    const rand = Math.random().toString(36).substring(2, 6);
    const row = {
      id: `nc-${univSuffix}-${ts}-${rand}-p${item.json.pageNumber}-${String.fromCharCode(97 + index)}`,
      universe_id: item.json.universeId,
      page_number: item.json.pageNumber,
      choice_order: index + 1,
      text: choice.text || '',
      created_at: item.json.createdAt
    };
    if (choice.next_page_number != null) row.next_page_number = choice.next_page_number;
    results.push({ json: row });
  });
}
return results;
